MoneyHubSettings.body:
{
    splitDepositSettingsByUserId(
      filter: {
        settingTypes: [RECURRENCE, DIRECT_DEPOSIT, DIRECT_DEPOSIT_INTENT]
        showHiddenEmployerSettings: true
      }
      normalizeToFrequency: MONTHLY
    ) {
      ... on SplitDepositDirectDepositIntentSetting {
        ...MoneyHubSplitDepositIntentSettingFragment
      }
      ... on SplitDepositDirectDepositSetting {
        ...MoneyHubSplitDepositDirectDepositSettingFragment
        monthlyTotals {
          ...DepositMonthlyTotalFragment
        }
      }
      ... on SplitDepositRecurrenceSetting {
        monthlyTotals {
          ...DepositMonthlyTotalFragment
        }
      }
      id
      isActive
      isHidden
      name
      allocations {
        allocationPercent
        targetAccountId
        targetAccountType
        nickname
        ... on SplitDepositDirectDepositAllocation {
          normalizedDailyAmount
        }
        ... on SplitDepositRecurrenceAllocation {
          legacyRecurrenceAmount {
            value
          }
          legacyRecurrenceRule {
            frequency
            ... on SplitDepositWeeklyRecurrenceRule {
              byWeekDay
            }
            ... on SplitDepositMonthlyRecurrenceRule {
              byMonthDay
            }
          }
          isActive
        }
      }
      deposits(orderBy: DESC, limit: 1) {
        ...MoneyHubSplitDepositFragment
      }
    }
    tierSubscriptionByUserId {
      id
      tierPrice {
        amount {
          value
        }
      }
      tier {
        id
        products {
          id
          name
          active
          key
        }
      }
    }
    investmentAccountsByUserId(filter: { product: EARLY }) {
      id
      beneficiaryId
      transferability {
        transferAge
        transferDate
      }
    }
    spendAccount {
      status
      isEligible
      isReopenable
      bankCardOrder {
        bankCardTier
      }
    }
    user {
      verified
      uuid
    }
  }

